// Hierarchical Bayesian model for binomial data (rat tumor style)
// y_i ~ Binomial(n_i, theta_i)
// theta_i ~ Beta(alpha, beta)
// Prior: p(alpha, beta) proportional to (alpha + beta)^(-5/2)
data {
  int<lower=0> N;              // number of observations (groups)
  array[N] int<lower=0> n;     // number of trials
  array[N] int<lower=0> y;     // number of successes
}
parameters {
  real<lower=0> alpha;
  real<lower=0> beta;
  vector<lower=0, upper=1>[N] theta;
}
model {
  // Prior on (alpha, beta): proportional to (alpha + beta)^(-5/2)
  target += -2.5 * log(alpha + beta);

  // Group-level probabilities
  theta ~ beta(alpha, beta);

  // Likelihood
  y ~ binomial(n, theta);
}
